Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
index.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict';

var rules = []

function type(obj) {
  return Object.prototype.toString.call(obj).slice(8, -1)
}

function addRule(match, result) {
  rules.unshift([match, result])
  return plural
}

// words like cherry, where a word ends in a y, but the letter before the y is a consonant
// also contains unique rule for words that end with 'quy' (soliloquy)
addRule(/[^aeiou]y$|quy$/i, function(w) { return w.substr(0, w.length - 1) + 'ies' })

// words that end with ch, x, s append 'es'
addRule(/x$|ch$|s$/i, function(w) { return w + 'es' })

// words that maintain latin/greek plural
addRule(/nucleus|syllabus|focus|fungus|cactus/i, function(w) { return w.substr(0, w.length - 2) + 'i' });
addRule(/thesis|crisis/i, function(w) { return w.substr(0, w.length - 2) + 'es' });
addRule(/appendix|index/i, function(w) { return w.substr(0, w.length - 2) + 'ices' });

// stereo -> stereos
   addRule(/[aeiouy]o/i, function(w) { return w + 's' });

addRule(/[^aeiouy]o$/i, function(w) { return w + 'es' });

// f/fe ending words gets switched to ves
// unless it's dwarf or roof
addRule(/(fe?$)/i, function(w, regex) {
  if (w === 'dwarf' || w === 'roof') {
    return w + 's'
  }
  return w.replace(regex, 'ves')
})

addRule('criterion', 'criteria')
addRule('bacterium', 'bacteria')
addRule('memo', 'memos')
addRule('cello', 'cellos')
addRule('die', 'dice')
addRule('goose', 'geese')
addRule('mouse', 'mice')
addRule('person', 'people')
addRule('chilli', 'chillies')

addRule(/^(?:wo)?man$/i, function(w) { return w.replace(/a/, 'e') })

// animals w/ no plural
addRule(/\b(?:bison|cod|deer|fowl|halibut|moose|sheep)\b/i, function(w) { return w })

// singular nouns that end in -s
var tools = ['goggle', 'scissor', 'plier', 'tong', 'tweezer']
var clothes = ['trouser', 'pant', 'pantie', 'clothe']
var games = ['billiard', 'bowl', 'card', 'dart', 'skittle', 'draught']
var illnesses = ['diabete', 'measle', 'mump', 'rabie', 'ricket', 'shingle']
var misc = ['kudo', 'premise', 'shamble', 'glasse', 'spectacle', 'jitter',
  'alm', 'fece', 'bowel', 'sud', 'entrail', 'electronic', 'outskirt', 'odd', 'tropic',
  'riche', 'surrounding', 'thank', 'heroic', 'remain', 'amend'
]
addRule(new RegExp('\\b(?:' + tools.concat(clothes, games, illnesses, misc).join('|') + ')s\\b', 'i'), function(w) { return w})

// most words ending in -ics are the same in their plural form
// mathematics, statistics, linguistics, classics, acoustics
addRule(/ics$/i, function(w) { return w })

// uncountable
addRule(/\b(?:tea|sugar|water|air|rice|knowledge|beauty|anger|fear|love|money|research|safety|evidence)\b/i, function(w) { return w })

function plural(word, num) {
  var i
    , rule

  if (num !== 1 || num === undefined) {
    for (i = 0; i < rules.length; i++) {
      rule = rules[i]

      if (type(rule[0]) === 'RegExp' && rule[0].test(word)) {
        return type(rule[1]) === 'Function' ? rule[1](word, rule[0]) : rule[1]
      }
      <PLACEHOLDER>
        return type(rule[1]) === 'Function' ? rule[1](word) : rule[1]
      }

    }

    return word + 's'
  }
  return word
}

module.exports = plural

module.exports.addRule = addRule

module.exports.unmonkeyPatch = function() {
  String.prototype.plural = null;
}

module.exports.monkeyPatch = function() {
  if (String.prototype.plural === undefined) {
    String.prototype.plural = function(num) {
      return plural(this, num)
    }
  }
  else {
    throw new Error('Unable to add plural function to String object')
  }
}

module.exports.VERSION = require('./package.json').version

In the original code, <PLACEHOLDER> has the value:

-           return type(rule[1]) === 'Function' ? rule[1](word) : rule[1]
In the mutated code, <PLACEHOLDER> has the value:

+           return false ? rule[1](word) : rule[1]


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/plural/attempt_1/pending_category/mutant-bb081ab/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

Looking at the mutation, the change is:

Original: `if (type(rule[0]) === 'String' && rule[0] === word) {`  
(inferred from context - the placeholder is the string matching branch)

The mutation changes:
```javascript
return type(rule[1]) === 'Function' ? rule[1](word) : rule[1]
```
to:
```javascript
return false ? rule[1](word) : rule[1]
```

Wait, let me re-read. The `<PLACEHOLDER>` is the condition before the return. Looking at the structure:

```javascript
if (type(rule[0]) === 'RegExp' && rule[0].test(word)) {
  return type(rule[1]) === 'Function' ? rule[1](word, rule[0]) : rule[1]
}
<PLACEHOLDER>
  return type(rule[1]) === 'Function' ? rule[1](word) : rule[1]
}
```

So the original `<PLACEHOLDER>` is `if (type(rule[0]) === 'String' && rule[0] === word) {` and the mutation changes the inner return to `return false ? rule[1](word) : rule[1]`.

The mutation means: when a string rule matches (like `addRule('criterion', 'criteria')`), instead of calling `rule[1](word)` when it's a function, it always returns `rule[1]` directly (since `false ? ... : rule[1]` always returns `rule[1]`).

But wait - for string rules like `addRule('criterion', 'criteria')`, `rule[1]` is `'criteria'` (a string, not a function). So `type(rule[1]) === 'Function'` would be false anyway, and both branches return `rule[1]`.

The mutation would matter if there's a string-matched rule where `rule[1]` is a function. Let me check - `addRule` with a string key and function value. Looking at the code, all string rules have string values. So the mutation might not matter for existing rules...

But `addRule` can be called with custom rules! Let me write a test that adds a string rule with a function result.

```typescript
import plural from "../../../../../../../../../../../subject_repositories/plural/index.js"

describe('plural string rule with function result', () => {
  it('should call the function when a string rule matches', () => {
    // Add a custom rule with a string match and function result
    const customWord = 'testword_unique_xyz'
    plural.addRule(customWord, function(w: string) { return w + '_pluralized' })

    const result = plural(customWord)
    expect(result).toBe(customWord + '_pluralized')
  })
})
```

```typescript
import plural from "../../../../../../../../../../../subject_repositories/plural/index.js"

describe('plural string rule with function result', () => {
  it('should call the function when a string rule with function value matches', () => {
    const customWord = 'uniquetestword123'
    plural.addRule(customWord, (w: string) => w + '_custom_plural')

    const result = plural(customWord)
    // Original: calls the function, returns 'uniquetestword123_custom_plural'
    // Mutated: returns the function itself (not called), which is not a string
    expect(result).toBe('uniquetestword123_custom_plural')
  })
})
```

