describe('plural', () => {
  it('should apply function result when string rule matches with function value', () => {
    const word = 'uniquetestword_abc987'
    plural.addRule(word, (w: string) => w + '_plural_form')

    const result = plural(word)
    expect(result).toBe('uniquetestword_abc987_plural_form')
  })
})
